# mkg/infrastructure/external/news_fetcher.py
"""Dummy news fetcher implementations.

Three source types matching the MKG architecture:
1. General news APIs (Reuters, Bloomberg syndication)
2. SEC/regulatory filings
3. Industry-specific RSS feeds

All return dummy data. Replace with real API calls when connected.
"""

import logging
from abc import ABC, abstractmethod
from datetime import datetime, timezone
from typing import Any
from uuid import uuid4

logger = logging.getLogger(__name__)


class NewsFetcher(ABC):
    """Abstract interface for news source fetchers."""

    @abstractmethod
    async def fetch(self, symbols: list[str] | None = None) -> list[dict[str, Any]]:
        """Fetch articles from this source.

        Args:
            symbols: Optional filter (company tickers or names).

        Returns:
            List of article dicts ready for ingestion pipeline.
        """
        ...

    @abstractmethod
    def source_name(self) -> str:
        """Return the human-readable source name."""
        ...


class DummyNewsApiFetcher(NewsFetcher):
    """Dummy general news API fetcher (Reuters, Bloomberg syndication, etc.)."""

    def source_name(self) -> str:
        return "dummy_news_api"

    async def fetch(self, symbols: list[str] | None = None) -> list[dict[str, Any]]:
        logger.info("DUMMY NewsAPI fetch: symbols=%s", symbols)
        # Return a sample article to prove the pipeline works
        return [
            {
                "id": str(uuid4()),
                "title": f"[DUMMY] Market update for {symbols[0] if symbols else 'general'}",
                "content": (
                    "This is a dummy article generated by the DummyNewsApiFetcher. "
                    "In production, this would be a real article from Reuters or "
                    "Bloomberg syndication about semiconductor supply chains."
                ),
                "source": self.source_name(),
                "url": f"https://dummy-news.example.com/{uuid4().hex[:8]}",
                "published_at": datetime.now(timezone.utc).isoformat(),
                "metadata": {"language": "en", "dummy": True},
            }
        ]


