class MultiSourceFetcher:
    """Aggregates multiple news fetchers into a single fetch call."""

    def __init__(self, fetchers: list[NewsFetcher] | None = None) -> None:
        self._fetchers = fetchers or [
            DummyNewsApiFetcher(),
            DummySecFilingFetcher(),
            DummyRssFetcher(),
        ]

    async def fetch_all(self, symbols: list[str] | None = None) -> list[dict[str, Any]]:
        """Fetch from all sources and merge results."""
        all_articles: list[dict[str, Any]] = []
        for fetcher in self._fetchers:
            try:
                articles = await fetcher.fetch(symbols)
                all_articles.extend(articles)
                logger.info(
                    "Fetched %d articles from %s", len(articles), fetcher.source_name()
                )
            except Exception:
                logger.exception("Failed to fetch from %s", fetcher.source_name())
        return all_articles

    @property
    def source_count(self) -> int:
        return len(self._fetchers)
